	const { theme } = useTheme();

	return (
		<>
			<ThemeContextProvider>
				{console.log(theme)}
				{/* <div className={ 'bg-slate-900 h-100'}> */}

				<LanguageProvider>
					<Router />
				</LanguageProvider>
				{/* </div> */}
			</ThemeContextProvider>
		</>
	);
}

export default App;
